const p = msg.payload || {};

const sessionId =
    p.session_id ||
    p.active_session ||
    flow.get("active_session") ||
    "S01";

flow.set("active_session", sessionId);
flow.set("session_has_drawing", p.session_has_drawing === true);

msg.session_id = sessionId;
msg.session_has_drawing = p.session_has_drawing === true;
msg.payload = p;

node.status({
    fill: "green",
    shape: "dot",
    text: `Ambiente ${sessionId}`
});

return msg;

const p = msg.payload || {};

const sessionId =
    p.session_id ||
    p.active_session ||
    flow.get("active_session") ||
    "S01";

flow.set("active_session", sessionId);

msg.session_id = sessionId;
msg.payload = p;

node.status({
    fill: "blue",
    shape: "dot",
    text: `Ejecutar ${sessionId}`
});

return msg;

const DATA_ROOT = "/home/pi/data"; // Cambiar si tu usuario no es pi

const sessionId =
    msg.session_id ||
    msg.payload?.session_id ||
    msg.payload?.active_session ||
    flow.get("active_session") ||
    "S01";

flow.set("active_session", sessionId);

const photoKey = `photo_count_${sessionId}`;
const candidateCount = (flow.get(photoKey) || 0) + 1;

const now = new Date();
const stamp = now.toISOString()
    .replace(/[-:]/g, "")
    .replace(/\.\d+Z$/, "Z");

const index = String(candidateCount).padStart(3, "0");

msg.session_id = sessionId;
msg.photo_count_candidate = candidateCount;

msg.url = "http://contracam.local/capture";
msg.method = "GET";

msg.filename = `${DATA_ROOT}/sessions/${sessionId}/photos/photo_${index}_${stamp}.jpg`;

msg.payload = null;

node.status({
    fill: "blue",
    shape: "dot",
    text: `${sessionId} foto ${index}`
});

return msg;

const sessionId =
    msg.session_id ||
    flow.get("active_session") ||
    "S01";

const photoCount =
    msg.photo_count_candidate ||
    flow.get(`photo_count_${sessionId}`) ||
    1;

flow.set(`photo_count_${sessionId}`, photoCount);
flow.set("photo_done", true);

const response = {
    type: "framework_state",

    session_id: sessionId,

    photo: true,
    photo_done: true,
    photo_count: photoCount,

    step: "photo",
    state: "done",
    message: `Foto ${String(photoCount).padStart(2, "0")} guardada`,
    progress: 25
};

if (flow.get("environment_done") === true) {
    response.environment = true;
    response.environment_done = true;
}

if (flow.get("session_has_drawing") === true) {
    response.session_has_drawing = true;
    response.drawing = true;
    response.drawing_done = true;
}

msg.payload = JSON.stringify(response);

msg.ip = "127.0.0.1";
msg.host = "127.0.0.1";
msg.port = 5006;

node.status({
    fill: "green",
    shape: "dot",
    text: `${sessionId} foto ${photoCount}`
});

return msg;

const sessionId =
    msg.session_id ||
    msg.payload?.session_id ||
    msg.payload?.active_session ||
    flow.get("active_session") ||
    "S01";

flow.set("active_session", sessionId);
flow.set("pending_environment_session", sessionId);

const toEsp32 = {
    payload: JSON.stringify({
        type: "command",
        command: "read_environment",
        source: "node-red",
        target: "contraenv",
        session_id: sessionId,
        timestamp: new Date().toISOString()
    }),

    ip: "contraenv.local",
    host: "contraenv.local",
    port: 4210
};

const toOled = {
    payload: JSON.stringify({
        type: "status",
        session_id: sessionId,
        step: "environment",
        state: "running",
        message: "Leyendo ambiente",
        progress: 30,
        environment: false,
        environment_done: false
    }),

    ip: "127.0.0.1",
    host: "127.0.0.1",
    port: 5006
};

return [toEsp32, toOled];

const DATA_ROOT = "/home/pi/data"; // Cambiar si tu usuario no es pi

const data = msg.payload;

if (!data || typeof data !== "object") {
    return [null, null];
}

if (data.type !== "environment") {
    return [null, null];
}

const sessionId =
    data.session_id ||
    flow.get("pending_environment_session") ||
    flow.get("active_session") ||
    "S01";

flow.set("active_session", sessionId);

// ----------------------------------------------------
// Progreso ambiental hacia OLED
// ----------------------------------------------------

if (data.state === "running") {
    const oledProgress = {
        payload: JSON.stringify({
            type: "status",
            session_id: sessionId,
            step: "environment",
            state: "running",
            message: data.message || "Leyendo ambiente",
            progress: data.progress || 35
        }),
        ip: "127.0.0.1",
        host: "127.0.0.1",
        port: 5006
    };

    return [null, oledProgress];
}

// ----------------------------------------------------
// Validar lectura final
// ----------------------------------------------------

if (data.stage !== "complete") {
    return [null, null];
}

const hasTemperature =
    data.temperature !== null &&
    data.temperature !== undefined &&
    !Number.isNaN(Number(data.temperature));

const hasHumidity =
    data.humidity !== null &&
    data.humidity !== undefined &&
    !Number.isNaN(Number(data.humidity));

const hasAQI =
    data.aqi !== null &&
    data.aqi !== undefined &&
    !Number.isNaN(Number(data.aqi));

const hasTVOC =
    data.tvoc !== null &&
    data.tvoc !== undefined &&
    !Number.isNaN(Number(data.tvoc));

const hasECO2 =
    data.eco2 !== null &&
    data.eco2 !== undefined &&
    !Number.isNaN(Number(data.eco2));

const hasAllValues =
    data.state === "done" &&
    data.aht_ok === true &&
    data.ens_ok === true &&
    hasTemperature &&
    hasHumidity &&
    hasAQI &&
    hasTVOC &&
    hasECO2;

if (!hasAllValues) {
    flow.set("environment_done", false);

    let errorMessage = "Lectura incompleta";

    if (data.aht_ok !== true) {
        errorMessage = "Error temp/hum";
    } else if (data.ens_ok !== true) {
        errorMessage = "ENS no estable";
    } else if (!hasAQI || !hasTVOC || !hasECO2) {
        errorMessage = "Faltan gases";
    }

    node.status({
        fill: "red",
        shape: "ring",
        text: errorMessage
    });

    const oledError = {
        payload: JSON.stringify({
            type: "status",
            session_id: sessionId,
            environment: false,
            environment_done: false,
            step: "environment",
            state: "error",
            message: errorMessage,
            progress: 35
        }),
        ip: "127.0.0.1",
        host: "127.0.0.1",
        port: 5006
    };

    return [null, oledError];
}

// ----------------------------------------------------
// Preparar guardado de lectura válida
// ----------------------------------------------------

const envKey = `environment_count_${sessionId}`;
const candidateCount = (flow.get(envKey) || 0) + 1;

const now = new Date();
const stamp = now.toISOString()
    .replace(/[-:]/g, "")
    .replace(/\.\d+Z$/, "Z");

const index = String(candidateCount).padStart(3, "0");

const envData = {
    ok: true,

    session_id: sessionId,
    index: candidateCount,

    type: data.type,
    device: data.device || "contraenv",
    hostname: data.hostname || "contraenv.local",
    ip: data.ip || null,

    state: data.state,
    stage: data.stage,
    message: data.message || "Ambiente listo",
    progress: data.progress || 50,

    aht_ok: true,
    ens_ok: true,

    temperature: Number(data.temperature),
    humidity: Number(data.humidity),

    ens_status: data.ens_status ?? null,
    aqi: Number(data.aqi),
    tvoc: Number(data.tvoc),
    eco2: Number(data.eco2),

    created_at: now.toISOString()
};

msg.session_id = sessionId;
msg.environment_count_candidate = candidateCount;
msg.environment_data = envData;

msg.filename = `${DATA_ROOT}/sessions/${sessionId}/environment/env_${index}_${stamp}.json`;
msg.payload = JSON.stringify(envData, null, 2);

node.status({
    fill: "green",
    shape: "dot",
    text: `${sessionId} env ${index}`
});

return [msg, null];

const p = msg.payload || {};

const sessionId =
    p.session_id ||
    p.active_session ||
    flow.get("active_session") ||
    "S01";

const hasDrawing = p.session_has_drawing === true;

flow.set("active_session", sessionId);
flow.set("session_has_drawing", hasDrawing);

msg.payload = JSON.stringify({
    type: "status",
    session_id: sessionId,
    step: "session",
    state: "done",
    message: hasDrawing ? `${sessionId} con dibujo` : `${sessionId} activa`,
    progress: 0,
    session_has_drawing: hasDrawing
});

msg.ip = "127.0.0.1";
msg.host = "127.0.0.1";
msg.port = 5006;

node.status({
    fill: "blue",
    shape: "dot",
    text: hasDrawing ? `${sessionId}*` : sessionId
});

return msg;

// Valida que la respuesta de la ESP32CAM sea una imagen JPEG real.
// Salida 1: foto válida hacia write file.
// Salida 2: error hacia OLED.

const sessionId =
    msg.session_id ||
    flow.get("active_session") ||
    "S01";

const payload = msg.payload;

const isBuffer = Buffer.isBuffer(payload);
const size = isBuffer ? payload.length : 0;

const looksLikeJpeg =
    isBuffer &&
    size > 2048 &&
    payload[0] === 0xFF &&
    payload[1] === 0xD8 &&
    payload[2] === 0xFF;

if (!looksLikeJpeg) {
    node.status({
        fill: "red",
        shape: "ring",
        text: `Foto inválida ${size} bytes`
    });

    const oledError = {
        payload: JSON.stringify({
            type: "status",
            session_id: sessionId,
            step: "photo",
            state: "error",
            message: "Foto invalida",
            progress: 20,
            photo: false,
            photo_done: false
        }),
        ip: "127.0.0.1",
        host: "127.0.0.1",
        port: 5006
    };

    return [null, oledError];
}

node.status({
    fill: "green",
    shape: "dot",
    text: `Foto OK ${Math.round(size / 1024)} KB`
});

return [msg, null];

const sessionId =
    msg.session_id ||
    flow.get("active_session") ||
    "S01";

const envCount =
    msg.environment_count_candidate ||
    flow.get(`environment_count_${sessionId}`) ||
    1;

flow.set(`environment_count_${sessionId}`, envCount);
flow.set("environment_done", true);

const envData = msg.environment_data || {};
flow.set("last_environment", envData);

const dataOut = {
    ...msg,
    payload: {
        ...envData,
        file: msg.filename,
        environment_count: envCount
    }
};

const oledOut = {
    payload: JSON.stringify({
        type: "framework_state",

        session_id: sessionId,

        environment: true,
        environment_done: true,
        environment_count: envCount,

        step: "environment",
        state: "done",
        message: `Amb ${String(envCount).padStart(2, "0")} guardado`,
        progress: 50
    }),

    ip: "127.0.0.1",
    host: "127.0.0.1",
    port: 5006
};

node.status({
    fill: "green",
    shape: "dot",
    text: `${sessionId} amb ${envCount}`
});

return [dataOut, oledOut];

// preparar_generate_drawing
// Salida 1: OLED
// Salida 2: exec Drawing

function sh(value) {
    return "'" + String(value).replace(/'/g, "'\\''") + "'";
}

if (flow.get("drawing_busy")) {
    const oledBusy = {
        payload: JSON.stringify({
            type: "screen",
            title: "DIBUJO",
            message: "Ya estoy generando..."
        }),
        ip: "127.0.0.1",
        host: "127.0.0.1",
        port: 5006
    };

    return [oledBusy, null];
}

const input = (msg.payload && typeof msg.payload === "object") ? msg.payload : {};

const session =
    input.session_id ||
    input.active_session ||
    input.session ||
    msg.session_id ||
    flow.get("active_session") ||
    flow.get("current_session") ||
    "S01";

flow.set("active_session", session);
flow.set("drawing_busy", true);
flow.set("drawing_session", session);

const execMsg = {
    session_id: session,
    payload: [
        "--session", sh(session),
        "--data-root", sh("/home/pi/data"),
        "--film-width-mm", "30",
        "--film-height-mm", "32",
        "--gcode-y-mode", "direct",
        "--path-start-corner", "top_right",
        "--landscape-bands", "4",
        "--internal-lines", "3",
        "--max-contours", "4"
    ].join(" ")
};

// No mandamos status todavía para no brincar a pantalla de estado.
// resultado_generate_drawing avisará cuando el dibujo y el G-code estén listos.
return [null, execMsg];

// resultado_generate_drawing

flow.set("drawing_busy", false);

let result;

try {
    result = JSON.parse(msg.payload);
} catch (err) {
    msg.payload = JSON.stringify({
        type: "status",
        step: "drawing",
        state: "error",
        message: "JSON invalido",
        screen: "status",
        command: "show_status"
    });

    msg.ip = "127.0.0.1";
    msg.host = "127.0.0.1";
    msg.port = 5006;

    return msg;
}

const sessionId =
    result.session_id ||
    msg.session_id ||
    flow.get("drawing_session") ||
    flow.get("active_session") ||
    "S01";

if (result.ok === true) {
    flow.set("drawing_done", true);
    flow.set("session_has_drawing", true);
    flow.set("gcode_done", true);
    flow.set("session_has_gcode", true);

    msg.payload = JSON.stringify({
        type: "framework_state",
        session_id: sessionId,

        drawing: true,
        drawing_done: true,
        session_has_drawing: true,

        gcode: true,
        gcode_done: true,
        session_has_gcode: true,

        screen: "status",
        command: "show_status",

        step: "drawing",
        state: "done",
        message: "Dibujo generado",
        progress: 75,

        svg: result.svg,
        preview: result.preview,
        gcode_path: result.gcode,
        metadata: result.metadata,
        generation_log: result.generation_log,
        steps: result.process_steps_dir
    });

    msg.ip = "127.0.0.1";
    msg.host = "127.0.0.1";
    msg.port = 5006;

    node.status({
        fill: "green",
        shape: "dot",
        text: `${sessionId} dibujo + G-code OK`
    });

    return msg;
}

flow.set("drawing_done", false);
flow.set("session_has_drawing", false);
flow.set("gcode_done", false);
flow.set("session_has_gcode", false);

msg.payload = JSON.stringify({
    type: "status",
    session_id: sessionId,

    drawing: false,
    drawing_done: false,
    session_has_drawing: false,

    gcode: false,
    gcode_done: false,
    session_has_gcode: false,

    step: "drawing",
    state: "error",
    message: result.message || "Error dibujo",
    screen: "status",
    command: "show_status"
});

msg.ip = "127.0.0.1";
msg.host = "127.0.0.1";
msg.port = 5006;

node.status({
    fill: "red",
    shape: "ring",
    text: `${sessionId} error dibujo`
});

return msg;

// error_generate_drawing
// Maneja errores impresos por stderr

flow.set("drawing_busy", false);

let errorText = "";

if (typeof msg.payload === "string") {
    errorText = msg.payload;
} else {
    errorText = JSON.stringify(msg.payload);
}

node.warn(errorText);

msg.payload = JSON.stringify({
    type: "oled",
    screen: "drawing_error",
    line1: "Error script",
    line2: errorText.slice(0, 18)
});

return msg;

// preparar_execute_drawing
// Salida 1: OLED
// Salida 2: exec Filmic

function sh(value) {
    return "'" + String(value).replace(/'/g, "'\\''") + "'";
}

const now = Date.now();
const startedAt = Number(flow.get("execution_started_at") || 0);
const staleMs = 10 * 60 * 1000;

if (flow.get("execution_busy") === true && startedAt && (now - startedAt) < staleMs) {
    const oledBusy = {
        payload: JSON.stringify({
            type: "screen",
            title: "DIBUJANDO",
            message: "Ejecucion en curso"
        }),
        ip: "127.0.0.1",
        host: "127.0.0.1",
        port: 5006
    };

    return [oledBusy, null];
}

// Si quedó un bloqueo viejo sin proceso activo, se limpia aquí.
flow.set("execution_busy", false);
flow.set("execution_started_at", 0);

const p = msg.payload || {};

const sessionId =
    p.session_id ||
    p.active_session ||
    msg.session_id ||
    flow.get("active_session") ||
    "S01";

flow.set("active_session", sessionId);
flow.set("execution_busy", true);
flow.set("execution_started_at", now);
flow.set("execution_done", false);
flow.set("drawing_executed", false);

const execMsg = {
    session_id: sessionId,
    payload: [
        "--session", sh(sessionId),
        "--data-root", sh("/home/pi/data"),
        "--port", sh("/dev/ttyACM0"),
        "--homing",
        "--calibrate-area",
        "--calibrate-x-dir", "1",
        "--calibrate-y-dir", "-1",
        "--calibration-step-mm", "4",
        "--calibration-fine-step-mm", "1",
        "--calibration-backoff-mm", "6",
        "--calibration-feed-mm-min", "350",
        "--calibration-fine-feed-mm-min", "180",
        "--fit-gcode-to-area",
        "--fit-margin-mm", "1",
        "--fit-mode", "uniform",
        "--set-work-zero",
        "--unlock"
    ].join(" ")
};

return [null, execMsg];

// resultado_execute_drawing
// Procesa JSONL emitido por Filmic

let lines = [];

if (typeof msg.payload === "string") {
    lines = msg.payload.split(/\r?\n/).filter(Boolean);
} else {
    lines = [JSON.stringify(msg.payload)];
}

let last = null;

for (const line of lines) {
    try {
        last = JSON.parse(line);
    } catch (err) {
        node.warn("Linea no JSON desde Filmic: " + line);
    }
}

if (!last) {
    return null;
}

const sessionId =
    last.session_id ||
    msg.session_id ||
    flow.get("active_session") ||
    "S01";

if (last.type === "execute_progress") {
    msg.payload = JSON.stringify({
        type: "status",
        session_id: sessionId,
        step: last.step || "execute",
        state: last.state || "running",
        message: last.message || "Ejecutando",
        progress: last.progress || 0
    });

    msg.ip = "127.0.0.1";
    msg.host = "127.0.0.1";
    msg.port = 5006;

    return msg;
}

if (last.ok === true && last.type === "execute_result") {
    flow.set("execution_busy", false);
flow.set("execution_started_at", 0);
    flow.set("execution_done", true);
    flow.set("drawing_executed", true);

    msg.payload = JSON.stringify({
        type: "framework_state",
        session_id: sessionId,

        drawing_executed: true,
        execution_done: true,
        executed: true,

        screen: "status",
        command: "show_status",

        step: "execute",
        state: "done",
        message: "Dibujo ejecutado",
        progress: 100,

        calibration: last.calibration || null
    });

    msg.ip = "127.0.0.1";
    msg.host = "127.0.0.1";
    msg.port = 5006;

    node.status({
        fill: "green",
        shape: "dot",
        text: `${sessionId} ejecutado`
    });

    return msg;
}

if (last.ok === false) {
    flow.set("execution_busy", false);
flow.set("execution_started_at", 0);
    flow.set("execution_done", false);
    flow.set("drawing_executed", false);

    msg.payload = JSON.stringify({
        type: "status",
        session_id: sessionId,
        step: "execute",
        state: "error",
        message: last.message || last.error || "Error ejecución",
        screen: "status",
        command: "show_status"
    });

    msg.ip = "127.0.0.1";
    msg.host = "127.0.0.1";
    msg.port = 5006;

    node.status({
        fill: "red",
        shape: "ring",
        text: `${sessionId} error ejecución`
    });

    return msg;
}

return null;

// error_execute_drawing

flow.set("execution_busy", false);
flow.set("execution_started_at", 0);
flow.set("execution_done", false);
flow.set("drawing_executed", false);

const sessionId =
    msg.session_id ||
    flow.get("active_session") ||
    "S01";

const errorText =
    typeof msg.payload === "string"
        ? msg.payload
        : JSON.stringify(msg.payload);

node.warn(errorText);

msg.payload = JSON.stringify({
    type: "status",
    session_id: sessionId,
    step: "execute",
    state: "error",
    message: errorText.slice(0, 40),
    screen: "status",
    command: "show_status"
});

msg.ip = "127.0.0.1";
msg.host = "127.0.0.1";
msg.port = 5006;

return msg;

// fin_execute_drawing
// Tercer output del exec Filmic: código de salida.

let rc = null;

if (typeof msg.payload === "number") {
    rc = msg.payload;
} else if (typeof msg.payload === "string" && msg.payload.trim() !== "") {
    rc = Number(msg.payload.trim());
} else if (msg.payload && typeof msg.payload === "object") {
    rc = Number(
        msg.payload.code ??
        msg.payload.rc ??
        msg.payload.returnCode ??
        msg.payload.exitCode
    );
}

// Si terminó bien, resultado_execute_drawing ya limpió estado y avisó a OLED.
if (rc === 0) {
    return null;
}

flow.set("execution_busy", false);
flow.set("execution_started_at", 0);
flow.set("execution_done", false);
flow.set("drawing_executed", false);

const sessionId =
    msg.session_id ||
    flow.get("active_session") ||
    "S01";

const shown = Number.isFinite(rc) ? `Filmic salio con codigo ${rc}` : "Filmic termino con error";

msg.payload = JSON.stringify({
    type: "status",
    session_id: sessionId,
    step: "execute",
    state: "error",
    message: shown,
    screen: "status",
    command: "show_status"
});

msg.ip = "127.0.0.1";
msg.host = "127.0.0.1";
msg.port = 5006;

node.status({
    fill: "red",
    shape: "ring",
    text: shown
});

return msg;
